mapper.delete:

delete from kh_disease_drug
where disease_id = #{diseaseId,jdbcType=BIGINT}
  and drug_id = #{drugId,jdbcType=BIGINT}

mapper.update:

update kh_disease_drug
set treate_desc = #{treateDesc,jdbcType=VARCHAR},
  create_time = #{createTime,jdbcType=TIMESTAMP},
  update_time = #{updateTime,jdbcType=TIMESTAMP}
where disease_id = #{diseaseId,jdbcType=BIGINT}
  and drug_id = #{drugId,jdbcType=BIGINT}

mapper.select:

select disease_id, drug_id, treate_desc, create_time, update_time
from kh_disease_drug
where disease_id = #{diseaseId,jdbcType=BIGINT}
  and drug_id = #{drugId,jdbcType=BIGINT}
